import React, { useState, useEffect } from 'react';
import { clientAPI } from '../../services/clientAPI';
import ClientOverview from './ClientOverview';
import ClientQuestionnaire from './ClientQuestionnaire';
import ClientDocuments from './ClientDocuments';
import './Client.css';

const NAV = [
  { id: 'overview',      label: 'Mon dossier',      icon: 'ti ti-layout-dashboard' },
  { id: 'questionnaire', label: 'Questionnaire',     icon: 'ti ti-clipboard-list' },
  { id: 'documents',     label: 'Documents',         icon: 'ti ti-file-upload' },
  { id: 'devis',         label: 'Devis',             icon: 'ti ti-file-invoice' },
];

export default function ClientDashboard() {
  const [active, setActive] = useState('overview');
  const [collapsed, setCollapsed] = useState(false);
  const [dossier, setDossier] = useState(null);
  const [dossierLoading, setDossierLoading] = useState(true);
  const [devis, setDevis] = useState(null);

  useEffect(() => {
    clientAPI.getDossier()
      .then((r) => setDossier(r.data))
      .catch(() => {})
      .finally(() => setDossierLoading(false));
  }, []);

  useEffect(() => {
    if (active === 'devis') {
      clientAPI.getDevis().then((r) => setDevis(r.data)).catch(() => {});
    }
  }, [active]);

  const handleLogout = () => {
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    window.location.href = '/login';
  };

  const PAGE_TITLES = {
    overview: 'Mon dossier',
    questionnaire: 'Questionnaire de risque',
    documents: 'Mes documents',
    devis: 'Mon devis',
  };

  return (
    <div className="cli-layout">
      {/* SIDEBAR */}
      <aside className={`cli-sidebar${collapsed ? ' collapsed' : ''}`}>
        <div className="cli-sidebar-brand">
          <div className="brand-icon"><i className="ti ti-user-shield" /></div>
          <span className="brand-text">Espace Client</span>
        </div>

        <nav className="cli-nav">
          {NAV.map((item) => (
            <button
              key={item.id}
              className={`cli-nav-btn${active === item.id ? ' cli-nav-btn--active' : ''}`}
              onClick={() => setActive(item.id)}
            >
              <i className={item.icon} aria-hidden="true" />
              <span>{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="cli-sidebar-footer">
          <button className="cli-nav-btn" onClick={handleLogout}>
            <i className="ti ti-logout" />
            <span>Déconnexion</span>
          </button>
          <button className="cli-collapse-btn" onClick={() => setCollapsed((c) => !c)}>
            <i className={`ti ${collapsed ? 'ti-layout-sidebar-right' : 'ti-layout-sidebar'}`} />
            <span>{collapsed ? '' : 'Réduire'}</span>
          </button>
        </div>
      </aside>

      {/* MAIN */}
      <div className="cli-main">
        <header className="cli-header">
          <h1>{PAGE_TITLES[active]}</h1>
          {dossier && (
            <span style={{ fontSize: 13, color: 'var(--cli-muted)' }}>
              {dossier.company}
            </span>
          )}
        </header>

        <div className="cli-content">
          {active === 'overview' && (
            dossierLoading
              ? <div className="cli-loading"><i className="ti ti-loader" /> Chargement...</div>
              : dossier
                ? <ClientOverview dossier={dossier} onNavigate={setActive} />
                : (
                  <div className="cli-empty">
                    <i className="ti ti-folder-off" />
                    <p>Aucun dossier associé à votre compte.<br />Contactez votre courtier.</p>
                  </div>
                )
          )}

          {active === 'questionnaire' && <ClientQuestionnaire />}

          {active === 'documents' && <ClientDocuments />}

          {active === 'devis' && (
            <div>
              {!devis && <div className="cli-loading"><i className="ti ti-loader" /> Chargement...</div>}
              {devis && devis.total === 0 && (
                <div className="cli-empty">
                  <i className="ti ti-file-off" />
                  <p>Aucun devis disponible pour le moment.</p>
                </div>
              )}
              {devis && devis.devis?.map((dv) => (
                <div key={dv.id} className="cli-devis-card" style={{ marginBottom: 16 }}>
                  <div style={{ fontSize: 12, color: 'var(--cli-muted)', marginBottom: 8 }}>DEVIS #{dv.id}</div>
                  <div className="cli-devis-prime">{dv.prime?.toLocaleString('fr-FR')} €</div>
                  <div className="cli-devis-label">Prime annuelle estimée</div>
                  <span className={`cli-badge cli-badge-${dv.status}`}>{dv.status}</span>
                  {dv.motif && (
                    <div style={{ marginTop: 12, padding: '10px 14px', background: 'rgba(255,68,102,0.08)', borderRadius: 8, fontSize: 13, color: '#ff6680' }}>
                      <i className="ti ti-info-circle" style={{ marginRight: 6 }} />
                      {dv.motif}
                    </div>
                  )}
                  <div style={{ fontSize: 12, color: 'var(--cli-muted)', marginTop: 10 }}>{dv.date}</div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
